prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?originalId ?normalizedId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "c41660388a04449a995dccf97d894f46" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:originalId ?originalId ;
         tai:normalizedId ?normalizedId .

  # “Parallel execution” heuristic: presence of a parallel gateway in the choreography
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .
  ?gw a bboExt:ParallelGateway ;
      tai:belongsTo ?choreo .
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?originalId ?normalizedId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "c41660388a04449a995dccf97d894f46" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }

  ?choreo tai:belongsTo ?model .
  FILTER EXISTS {
    SELECT (COUNT(*) AS ?parallelGws) WHERE {
      ?gw a bboExt:ParallelGateway .
      ?gw tai:belongsTo ?choreo .
    }
  }
}
ORDER BY DESC(?created)
LIMIT 25
